import React from 'react';
import './Works.css';

const dummyWorks = [
  '作品A', '作品B', '作品C', '作品D', '作品E', '作品F', '作品G', '作品H', '作品I', '作品J', '作品K', '作品L'
];

function Works() {
  return (
    <div className="works-container">
      <h2>作品一覧</h2>
      <div className="works-list">
        {dummyWorks.map((work, idx) => (
          <button className="work-btn" key={idx}>{work}</button>
        ))}
      </div>
    </div>
  );
}

export default Works;
